class Solution {
public:
    int rand10() {
        while (true) {
            int a = rand7();
            int b = rand7();
            int combined = (a - 1) * 7 + b;
            if (combined <= 40) {
                return (combined - 1) % 10 + 1;
            }
        }
    }
};

